I solved this problem by using puppeteer to go through all my route after running `npm run dev` using concurrently package to both command at the same time

![Image](https://github.com/user-attachments/assets/a9c11c02-b732-49f0-85fd-4f8b55d7c85c)

// precompile.js
import puppeteer from 'puppeteer';
import http from 'http';

const routes = [
//routes
    '/',
];


const checkServer = (url) => {

    return new Promise((resolve, reject) => {
        const req = http.get(url, (res) => {
            if (res.statusCode === 200) {
                resolve(true);
            } else {
                reject(false);
            }
        });

        req.on('error', () => resolve(false));
        req.end();
    });
};

(async () => {

    const serverUrl = 'http://localhost:3500';
    const serverRunning = await checkServer(serverUrl);
    if (!serverRunning) {
        console.error('Server is not running. Please start the server and try again.');
        process.exit(1);
    }

    const browser = await puppeteer.launch();
    const page = await browser.newPage();
    page.setDefaultNavigationTimeout(15000);
    page.setDefaultTimeout(15000);

    const retryVisit = async (url, retries = 3) => {
        for (let attempt = 1; attempt <= retries; attempt++) {
            try {
                await page.goto(url, { waitUntil: 'networkidle0' });
                return;
            } catch (error) {
                if (attempt === retries) {
                    console.error(`Failed to visit ${url} after ${retries} attempts: ${error.message}`);
                } else {
                    console.log(`Retrying ${url} (attempt ${attempt} of ${retries})`);
                }
            }
        }
    };

    for (const route of routes) {
        const url = `${serverUrl}${route}`;
        console.log(`Visiting ${url}`);
        await retryVisit(url);
    }

    await browser.close();
})();

